import{_ as a,o as s,c as i,ak as t}from"./chunks/framework.Dpc0wyhY.js";const u=JSON.parse('{"title":"Access Files","description":"","frontmatter":{},"headers":[],"relativePath":"files/access.md","filePath":"files/access.md"}'),o={name:"files/access.md"};function n(l,e,r,c,d,h){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="access-files" tabindex="-1">Access Files <a class="header-anchor" href="#access-files" aria-label="Permalink to “Access Files”">​</a></h1><p>Learn how to retrieve and download files from your Likha ERP instance. Folders and file information are stored in regular collections, which means user and role access permissions are fully configurable and granular on both folders and files.</p><h2 id="access-a-file" tabindex="-1">Access a File <a class="header-anchor" href="#access-a-file" aria-label="Permalink to “Access a File”">​</a></h2><p>The uploaded file is immediately available via the management interface for users with the correct access control. From here, you can download, edit, or replace files.</p><p>You can access files via URL in your applications by using the following URL pattern:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://your-domain.com/assets/&lt;file-id&gt;</span></span></code></pre></div><p>If the public role has read access, the file is publicly accessible. Otherwise, you may need to include an access token in the request.</p><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to “Authentication”">​</a></h3><p>The system leverages stored cookies to authenticate when accessing files, when present.</p><p>If no cookie is stored, you can use the <code>access_token</code> query parameter to authenticate, provided the token belongs to a user with the required access to read the file.</p><h3 id="seo-friendly-urls" tabindex="-1">SEO-Friendly URLs <a class="header-anchor" href="#seo-friendly-urls" aria-label="Permalink to “SEO-Friendly URLs”">​</a></h3><p>You can provide an optional filename after the UUID to optimize for SEO, for example:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://your-domain.com/assets/&lt;file-id&gt;/&lt;filename&gt;</span></span></code></pre></div><p>For example:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://your-domain.com/assets/1ac73658-8b62-4dea-b6da-529fbc9d01a4/logo.png</span></span></code></pre></div><p>This optional filename is also used in the <code>Content-Disposition</code> header when the <code>?download</code> query parameter is used.</p><blockquote><p><strong>Direct File Access</strong></p><p>While you may technically be able to expose your storage adapters root file system and access your raw files through there, it is recommended that you always use the API. This is the only way that you can take advantage of file permissions and other built-in features.</p></blockquote><h3 id="downloading-a-file" tabindex="-1">Downloading a File <a class="header-anchor" href="#downloading-a-file" aria-label="Permalink to “Downloading a File”">​</a></h3><p>To download an asset with the correct filename, you need to add the <code>?download</code> query parameter to the request and the <code>download</code> attribute to your anchor tag. This will ensure the appropriate <code>Content-Disposition</code> headers are added. Without this, the download will work on the same domain, however it will have the file&#39;s &quot;id&quot; as the filename for cross-origin requests.</p><p>Fetching transformed assets is done by adding a <code>key</code> query parameter to the original file&#39;s URL. In the management interface, you can configure different asset presets that control the output of any given image. If a requested transformed asset doesn&#39;t yet exist, it is dynamically generated and immediately returned.</p>',20)])])}const f=a(o,[["render",n]]);export{u as __pageData,f as default};
